"use client";

import { usePathname } from "next/navigation";
import Link from "next/link";
import { Home, List, PiggyBank, Settings, Info } from "lucide-react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";
import { useState } from "react";
import { AppInfoSheet } from "@/components/ui/AppInfoSheet";

const tabs = [
    { href: "/", label: "Home", icon: Home },
    { href: "/expenses", label: "Expenses", icon: List },
    { href: "/budgets", label: "Budgets", icon: PiggyBank },
    { href: "/settings", label: "Settings", icon: Settings },
];

export function DesktopSidebar() {
    const pathname = usePathname();
    const [infoOpen, setInfoOpen] = useState(false);

    return (
        <>
            <aside className="hidden md:flex flex-col w-64 h-dvh sticky top-0 border-r ios-separator ios-glass pb-6">
                {/* Branding / App Info */}
                <div className="p-6 pb-2 flex flex-col items-center">
                    <img src="/logo.png?v=2" alt="Agent Oasis Logo" className="w-20 h-20 rounded-[20px] shadow-sm mb-3" />
                    <h1 className="text-xl font-bold ios-text-primary tracking-tight">Agent Oasis</h1>
                    <p className="text-xs ios-text-secondary font-medium tracking-wide">AI EXPENSE TRACKER</p>
                </div>

                {/* Navigation Links */}
                <nav className="flex-1 px-4 space-y-2 mt-4">
                    {tabs.map(({ href, label, icon: Icon }) => {
                        const isActive = pathname === href;
                        return (
                            <Link
                                key={href}
                                href={href}
                                className={cn(
                                    "flex items-center gap-3 px-4 py-3 rounded-ios-sm transition-all duration-200 font-medium",
                                    isActive
                                        ? "bg-ios-blue text-white shadow-md shadow-ios-blue/20"
                                        : "ios-text-secondary hover:bg-[#F2F2F7] dark:hover:bg-[#2C2C2E] hover:text-ios-primary"
                                )}
                            >
                                <Icon size={20} strokeWidth={isActive ? 2.5 : 2} />
                                {label}
                            </Link>
                        );
                    })}
                </nav>

                {/* App Info Action Area */}
                <div className="px-4 mt-auto">
                    <motion.button
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => setInfoOpen(true)}
                        className="w-full relative flex items-center justify-center gap-2 py-3 rounded-ios-sm bg-[#F2F2F7] dark:bg-[#2C2C2E] ios-text-secondary hover:text-ios-primary transition-colors font-semibold"
                    >
                        <Info size={18} strokeWidth={2.5} />
                        About Agent Oasis
                    </motion.button>
                </div>
            </aside>

            <AppInfoSheet open={infoOpen} onOpenChange={setInfoOpen} />
        </>
    );
}
